import{_ as t,c as a,o,a1 as d}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"驗證失敗: 401 錯誤排查 | Antigravity-Manager","description":"學習 Antigravity Tools 代理的驗證機制，排查 401 錯誤。按 auth_mode、api_key、Header 順序定位問題，了解 auto 模式規則與 /healthz 豁免，避免 Header 優先級誤判。","frontmatter":{"title":"驗證失敗: 401 錯誤排查 | Antigravity-Manager","sidebarTitle":"3 分鐘搞定 401","subtitle":"401/驗證失敗：先看 auth_mode，再看 Header","description":"學習 Antigravity Tools 代理的驗證機制，排查 401 錯誤。按 auth_mode、api_key、Header 順序定位問題，了解 auto 模式規則與 /healthz 豁免，避免 Header 優先級誤判。","tags":["FAQ","驗證","401","API Key"],"prerequisite":["start-proxy-and-first-client"],"order":2},"headers":[],"relativePath":"zh-tw/lbjlaq/Antigravity-Manager/faq/auth-401/index.md","filePath":"zh-tw/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"}'),r={name:"zh-tw/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"};function i(s,e,l,c,h,n){return o(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="_401-驗證失敗-先看-auth-mode-再看-header" tabindex="-1">401/驗證失敗：先看 auth_mode，再看 Header <a class="header-anchor" href="#_401-驗證失敗-先看-auth-mode-再看-header" aria-label="Permalink to &quot;401/驗證失敗：先看 auth_mode，再看 Header&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>3 分鐘內判斷 401 是不是被 Antigravity Tools 的驗證中介軟體攔下</li><li>弄清 <code>proxy.auth_mode</code> 四種模式（尤其是 <code>auto</code>）在你當前配置下的「實際生效值」</li><li>用正確的 API Key Header（以及避免 Header 優先級坑）讓請求通過</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>客戶端呼叫本地反代時收到 <code>401 Unauthorized</code> 錯誤：</p><ul><li>Python/OpenAI SDK：拋出 <code>AuthenticationError</code></li><li>curl：返回 <code>HTTP/1.1 401 Unauthorized</code></li><li>HTTP 客戶端：響應狀態碼 401</li></ul><h2 id="什麼是-401-驗證失敗" tabindex="-1">什麼是 401/驗證失敗？ <a class="header-anchor" href="#什麼是-401-驗證失敗" aria-label="Permalink to &quot;什麼是 401/驗證失敗？&quot;">​</a></h2><p><strong>401 Unauthorized</strong> 在 Antigravity Tools 裡最常見的含義是：代理啟用了驗證（由 <code>proxy.auth_mode</code> 決定），但請求沒有帶對 API Key，或帶了一個優先級更高但不匹配的 Header，於是 <code>auth_middleware()</code> 直接返回 401。</p><div class="info custom-block"><p class="custom-block-title">先確認是不是「代理在攔」</p><p>上游平台也可能返回 401，但這篇 FAQ 只處理「代理驗證導致的 401」。你可以先用下面的 <code>/healthz</code> 快速分辨。</p></div><h2 id="快速排查-按這個順序做" tabindex="-1">快速排查（按這個順序做） <a class="header-anchor" href="#快速排查-按這個順序做" aria-label="Permalink to &quot;快速排查（按這個順序做）&quot;">​</a></h2><h3 id="第-1-步-用-healthz-判斷「驗證是否在攔你」" tabindex="-1">第 1 步：用 <code>/healthz</code> 判斷「驗證是否在攔你」 <a class="header-anchor" href="#第-1-步-用-healthz-判斷「驗證是否在攔你」" aria-label="Permalink to &quot;第 1 步：用 `/healthz` 判斷「驗證是否在攔你」&quot;">​</a></h3><p><strong>為什麼</strong><code>all_except_health</code> 會放行 <code>/healthz</code>，但會攔住其他路由；這能幫你快速定位 401 是否來自代理驗證層。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 不帶任何驗證 Header</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/healthz</span></span></code></pre></div><p><strong>你應該看到</strong></p><ul><li><code>auth_mode=all_except_health</code>（或 <code>auto</code> 且 <code>allow_lan_access=true</code>）時：通常會返回 <code>200</code></li><li><code>auth_mode=strict</code> 時：會返回 <code>401</code></li></ul><div class="tip custom-block"><p class="custom-block-title"><code>/healthz</code> 在路由層是 GET</p><p>代理在路由裡註冊的是 <code>GET /healthz</code>（見 <code>src-tauri/src/proxy/server.rs</code>）。</p></div><hr><h3 id="第-2-步-確認-auth-mode-的「實際生效值」-尤其是-auto" tabindex="-1">第 2 步：確認 <code>auth_mode</code> 的「實際生效值」（尤其是 <code>auto</code>） <a class="header-anchor" href="#第-2-步-確認-auth-mode-的「實際生效值」-尤其是-auto" aria-label="Permalink to &quot;第 2 步：確認 `auth_mode` 的「實際生效值」（尤其是 `auto`）&quot;">​</a></h3><p><strong>為什麼</strong><code>auto</code> 不是一個「獨立策略」，它會根據 <code>allow_lan_access</code> 計算出真正要執行的模式。</p><table tabindex="0"><thead><tr><th><code>proxy.auth_mode</code></th><th>額外條件</th><th>實際生效值（effective mode）</th></tr></thead><tbody><tr><td><code>off</code></td><td>-</td><td><code>off</code></td></tr><tr><td><code>strict</code></td><td>-</td><td><code>strict</code></td></tr><tr><td><code>all_except_health</code></td><td>-</td><td><code>all_except_health</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=false</code></td><td><code>off</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=true</code></td><td><code>all_except_health</code></td></tr></tbody></table><p><strong>你可以在 GUI 的 API Proxy 頁面檢查</strong>：<code>Allow LAN Access</code> 和 <code>Auth Mode</code>。</p><hr><h3 id="第-3-步-確認-api-key-不是空的-並且你用的是同一個值" tabindex="-1">第 3 步：確認 <code>api_key</code> 不是空的，並且你用的是同一個值 <a class="header-anchor" href="#第-3-步-確認-api-key-不是空的-並且你用的是同一個值" aria-label="Permalink to &quot;第 3 步：確認 `api_key` 不是空的，並且你用的是同一個值&quot;">​</a></h3><p><strong>為什麼</strong> 驗證開啟時，如果 <code>proxy.api_key</code> 為空，<code>auth_middleware()</code> 會直接拒絕全部請求並打錯誤日誌。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proxy auth is enabled but api_key is empty; denying request</span></span></code></pre></div><p><strong>你應該看到</strong></p><ul><li>API Proxy 頁面裡能看到一個以 <code>sk-</code> 開頭的 key（預設值在 <code>ProxyConfig::default()</code> 會自動生成）</li><li>點擊「Regenerate/編輯」保存後，外部請求立刻按新 key 校驗（無需重啟）</li></ul><hr><h3 id="第-4-步-用最簡單的-header-試一次-先別用複雜-sdk" tabindex="-1">第 4 步：用最簡單的 Header 試一次（先別用複雜 SDK） <a class="header-anchor" href="#第-4-步-用最簡單的-header-試一次-先別用複雜-sdk" aria-label="Permalink to &quot;第 4 步：用最簡單的 Header 試一次（先別用複雜 SDK）&quot;">​</a></h3><p><strong>為什麼</strong> 中介軟體會優先讀取 <code>Authorization</code>，再讀 <code>x-api-key</code>，最後讀 <code>x-goog-api-key</code>。如果你同時發了多個 Header，前面的那個錯了，後面的那個就算對也不會被用上。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 推薦寫法：Authorization + Bearer</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><p><strong>你應該看到</strong>：<code>HTTP/1.1 200 OK</code>（或至少不再是 401）</p><div class="info custom-block"><p class="custom-block-title">代理對 Authorization 的相容細節</p><p><code>auth_middleware()</code> 會把 <code>Authorization</code> 的值按 <code>Bearer </code> 前綴做一次剝離；如果沒有 <code>Bearer </code> 前綴，也會把整個值當成 key 去比對。文件仍推薦 <code>Authorization: Bearer &lt;key&gt;</code>（更符合通用 SDK 約定）。</p></div><p><strong>如果你必須用 <code>x-api-key</code></strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-api-key: sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><hr><h2 id="常見坑-都是原始碼裡真實會發生的" tabindex="-1">常見坑（都是原始碼裡真實會發生的） <a class="header-anchor" href="#常見坑-都是原始碼裡真實會發生的" aria-label="Permalink to &quot;常見坑（都是原始碼裡真實會發生的）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>現象</th><th>真實原因</th><th>該怎麼改</th></tr></thead><tbody><tr><td><code>auth_mode=auto</code>，但本機呼叫仍然 401</td><td><code>allow_lan_access=true</code> 導致 <code>auto</code> 生效為 <code>all_except_health</code></td><td>關閉 <code>allow_lan_access</code>，或讓客戶端帶上 key</td></tr><tr><td>你覺得「我明明帶了 x-api-key」，但仍 401</td><td>同時帶了一個不匹配的 <code>Authorization</code>，中介軟體優先用它</td><td>刪掉多餘 Header，只保留一個你確定正確的</td></tr><tr><td><code>Authorization: Bearer&lt;key&gt;</code> 仍 401</td><td><code>Bearer</code> 後少了空格，無法按 <code>Bearer </code> 前綴剝離</td><td>改成 <code>Authorization: Bearer &lt;key&gt;</code></td></tr><tr><td>所有請求都 401，日誌出現 <code>api_key is empty</code></td><td><code>proxy.api_key</code> 為空</td><td>在 GUI 裡重新生成/設置一個非空 key</td></tr></tbody></table><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><ul><li>先用 <code>/healthz</code> 定位 401 是否來自代理驗證層</li><li>再確認 <code>auth_mode</code>（尤其是 <code>auto</code> 的 effective mode）</li><li>最後只帶一個確定正確的 Header 去驗證（避免 Header 優先級坑）</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../429-rotation/">429/容量錯誤：帳號輪換的正確預期與模型容量耗盡的誤區</a></strong>。</p><p>你會學到：</p><ul><li>429 到底是「配額不足」還是「上游限流」</li><li>帳號輪換的正確預期（什麼時候會自動切、什麼時候不會）</li><li>用配置把 429 的機率壓下去</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>ProxyAuthMode 枚舉</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L5-L18" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>5-18</td></tr><tr><td>ProxyConfig: allow_lan_access/auth_mode/api_key 與預設值</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-258</td></tr><tr><td>auto 模式解析（effective_auth_mode）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/security.rs#L1-L30" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/security.rs</code></a></td><td>1-30</td></tr><tr><td>驗證中介軟體（Header 提取與優先級、/healthz 豁免、OPTIONS 放行）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/auth.rs#L14-L77" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/auth.rs</code></a></td><td>14-77</td></tr><tr><td>/healthz 路由註冊與中介軟體順序</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L170-L193" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>170-193</td></tr><tr><td>驗證文件（模式與客戶端約定）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy/auth.md#L1-L45" target="_blank" rel="noreferrer"><code>docs/proxy/auth.md</code></a></td><td>1-45</td></tr></tbody></table><p><strong>關鍵枚舉</strong>：</p><ul><li><code>ProxyAuthMode::{Off, Strict, AllExceptHealth, Auto}</code>：驗證模式</li></ul><p><strong>關鍵函式</strong>：</p><ul><li><code>ProxySecurityConfig::effective_auth_mode()</code>：把 <code>auto</code> 解析成真實策略</li><li><code>auth_middleware()</code>：執行驗證（含 Header 提取順序與 /healthz 豁免）</li></ul></details>',45)])])}const g=t(r,[["render",i]]);export{u as __pageData,g as default};
